const http=require("node:http");const fs=require("node:fs");const path=require("node:path");const crypto=require("node:crypto");const {spawn}=require("node:child_process");const {DatabaseSync}=require("node:sqlite");if(typeof process.loadEnvFile==="function"&&fs.existsSync(".env"))try{process.loadEnvFile(".env")}catch(e){if(process.env.NODE_ENV==="production")throw e}const {createPaymentProvider}=require("./payments/provider");const paymentProvider=createPaymentProvider();function validateRuntimeConfig(){if(!["production","staging"].includes(process.env.NODE_ENV))return;const missing=[];if(!process.env.APP_BASE_URL||!/^https:\/\//i.test(process.env.APP_BASE_URL))missing.push("APP_BASE_URL (must be an https URL)");if(!process.env.DOCUMENT_ENCRYPTION_KEY)missing.push("DOCUMENT_ENCRYPTION_KEY");if(!process.env.CARRIER_WEBHOOK_SECRET)missing.push("CARRIER_WEBHOOK_SECRET");if(process.env.EMAIL_PROVIDER==="resend"&&(!process.env.RESEND_API_KEY||!process.env.EMAIL_FROM))missing.push("RESEND_API_KEY and EMAIL_FROM");if(!["resend","development"].includes(process.env.EMAIL_PROVIDER))missing.push("EMAIL_PROVIDER");if(process.env.PAYMENTS_PROVIDER==="paystack"&&!process.env.PAYSTACK_SECRET_KEY)missing.push("PAYSTACK_SECRET_KEY");if(missing.length)throw Error(`Missing deployment configuration: ${missing.join(", ")}`)}validateRuntimeConfig();
const ROOT=__dirname,DATA=process.env.SOKO_DATA_DIR?path.resolve(process.env.SOKO_DATA_DIR):path.join(ROOT,"data");fs.mkdirSync(DATA,{recursive:true});const db=new DatabaseSync(path.join(DATA,"soko.db"));db.exec("PRAGMA foreign_keys=ON; PRAGMA journal_mode=WAL");
db.exec(`CREATE TABLE IF NOT EXISTS users(id INTEGER PRIMARY KEY,email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,role TEXT NOT NULL CHECK(role IN('buyer','merchant','admin')),name TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS sessions(token_hash TEXT PRIMARY KEY,user_id INTEGER NOT NULL,expires_at INTEGER NOT NULL,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS merchants(id INTEGER PRIMARY KEY,user_id INTEGER UNIQUE NOT NULL,store_name TEXT NOT NULL,country TEXT NOT NULL CHECK(country IN('Nigeria','Ghana','Kenya')),description TEXT DEFAULT '',verified INTEGER DEFAULT 0,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS products(id INTEGER PRIMARY KEY,merchant_id INTEGER NOT NULL,name TEXT NOT NULL,category TEXT NOT NULL,price INTEGER NOT NULL CHECK(price>0),stock INTEGER NOT NULL DEFAULT 0 CHECK(stock>=0),emoji TEXT DEFAULT '◇',color TEXT DEFAULT '#d9e3c6',description TEXT DEFAULT '',active INTEGER DEFAULT 1,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(merchant_id) REFERENCES merchants(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS orders(id TEXT PRIMARY KEY,buyer_id INTEGER NOT NULL,merchant_id INTEGER NOT NULL,currency TEXT NOT NULL,total INTEGER NOT NULL,status TEXT NOT NULL DEFAULT 'Payment confirmed',customer_name TEXT NOT NULL,destination TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(buyer_id) REFERENCES users(id),FOREIGN KEY(merchant_id) REFERENCES merchants(id));CREATE TABLE IF NOT EXISTS order_items(id INTEGER PRIMARY KEY,order_id TEXT NOT NULL,product_id INTEGER NOT NULL,quantity INTEGER NOT NULL DEFAULT 1,price INTEGER NOT NULL,FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,FOREIGN KEY(product_id) REFERENCES products(id));`);
function addColumn(table,column,definition){if(!db.prepare(`PRAGMA table_info(${table})`).all().some(c=>c.name===column))db.exec(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`)}addColumn("merchants","status","TEXT NOT NULL DEFAULT 'pending'");addColumn("products","moderation_status","TEXT NOT NULL DEFAULT 'pending'");addColumn("orders","dispute_status","TEXT NOT NULL DEFAULT 'none'");addColumn("orders","dispute_reason","TEXT NOT NULL DEFAULT ''");db.exec("CREATE TABLE IF NOT EXISTS audit_logs(id INTEGER PRIMARY KEY,admin_id INTEGER NOT NULL,action TEXT NOT NULL,target_type TEXT NOT NULL,target_id TEXT NOT NULL,details TEXT DEFAULT '',created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(admin_id) REFERENCES users(id))");db.prepare("UPDATE merchants SET status='approved' WHERE verified=1 AND status='pending'").run();db.prepare("UPDATE products SET moderation_status='approved' WHERE merchant_id IN (SELECT id FROM merchants WHERE verified=1) AND moderation_status='pending'").run();
addColumn("orders","subtotal","INTEGER NOT NULL DEFAULT 0");addColumn("orders","delivery_fee","INTEGER NOT NULL DEFAULT 0");addColumn("orders","service_fee","INTEGER NOT NULL DEFAULT 0");addColumn("orders","merchant_amount","INTEGER NOT NULL DEFAULT 0");db.exec("CREATE TABLE IF NOT EXISTS payments(id INTEGER PRIMARY KEY,order_id TEXT UNIQUE NOT NULL,reference TEXT UNIQUE NOT NULL,provider TEXT NOT NULL DEFAULT 'development-provider',expected_amount INTEGER NOT NULL,received_amount INTEGER NOT NULL DEFAULT 0,currency TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'awaiting_payment',confirmed_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS provider_events(event_id TEXT PRIMARY KEY,event_type TEXT NOT NULL,payment_id INTEGER,payload TEXT NOT NULL,processed_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(payment_id) REFERENCES payments(id));CREATE TABLE IF NOT EXISTS ledger_entries(id INTEGER PRIMARY KEY,payment_id INTEGER,order_id TEXT NOT NULL,entry_type TEXT NOT NULL,account TEXT NOT NULL,direction TEXT NOT NULL CHECK(direction IN('debit','credit')),amount INTEGER NOT NULL CHECK(amount>=0),currency TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(payment_id) REFERENCES payments(id),FOREIGN KEY(order_id) REFERENCES orders(id));CREATE TABLE IF NOT EXISTS payouts(id INTEGER PRIMARY KEY,order_id TEXT UNIQUE NOT NULL,merchant_id INTEGER NOT NULL,amount INTEGER NOT NULL,currency TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'submitted',provider_reference TEXT UNIQUE NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,paid_at TEXT,FOREIGN KEY(order_id) REFERENCES orders(id),FOREIGN KEY(merchant_id) REFERENCES merchants(id))");
addColumn("merchants","commission_bps","INTEGER");addColumn("orders","commission_amount","INTEGER NOT NULL DEFAULT 0");db.exec("CREATE TABLE IF NOT EXISTS delivery_rates(id INTEGER PRIMARY KEY,merchant_id INTEGER NOT NULL,destination TEXT NOT NULL,amount INTEGER NOT NULL CHECK(amount>=0),UNIQUE(merchant_id,destination),FOREIGN KEY(merchant_id) REFERENCES merchants(id) ON DELETE CASCADE)");const demoMerchant=db.prepare("SELECT id FROM merchants WHERE store_name='Amara Organics'").get();if(demoMerchant&&!db.prepare("SELECT id FROM delivery_rates WHERE merchant_id=? LIMIT 1").get(demoMerchant.id)){const addRate=db.prepare("INSERT INTO delivery_rates(merchant_id,destination,amount) VALUES(?,?,?)");addRate.run(demoMerchant.id,"United Kingdom",6000);addRate.run(demoMerchant.id,"United States",8500);addRate.run(demoMerchant.id,"Canada",8000);addRate.run(demoMerchant.id,"Australia",9500);addRate.run(demoMerchant.id,"France",7000);addRate.run(demoMerchant.id,"Germany",7000);addRate.run(demoMerchant.id,"Other European country",7500)}
addColumn("merchants","payout_recipient_code","TEXT");addColumn("merchants","payout_account_last4","TEXT");addColumn("payments","authorization_url","TEXT");addColumn("payments","access_code","TEXT");addColumn("payments","provider_reference","TEXT");
addColumn("products","image_url","TEXT");db.exec("CREATE TABLE IF NOT EXISTS product_variants(id INTEGER PRIMARY KEY,product_id INTEGER NOT NULL,name TEXT NOT NULL,value TEXT NOT NULL,stock INTEGER NOT NULL DEFAULT 0,price_adjustment INTEGER NOT NULL DEFAULT 0,UNIQUE(product_id,name,value),FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS favorites(user_id INTEGER NOT NULL,product_id INTEGER NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(user_id,product_id),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE)");
addColumn("orders","expires_at","TEXT");addColumn("order_items","variant_id","INTEGER");addColumn("order_items","variant_label","TEXT");db.exec("CREATE TABLE IF NOT EXISTS product_images(id INTEGER PRIMARY KEY,product_id INTEGER NOT NULL,url TEXT NOT NULL,position INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(product_id) REFERENCES products(id) ON DELETE CASCADE)");
db.exec("CREATE TABLE IF NOT EXISTS refunds(id INTEGER PRIMARY KEY,order_id TEXT UNIQUE NOT NULL,payment_id INTEGER NOT NULL,amount INTEGER NOT NULL,currency TEXT NOT NULL,status TEXT NOT NULL,provider_reference TEXT,reason TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,processed_at TEXT,FOREIGN KEY(order_id) REFERENCES orders(id),FOREIGN KEY(payment_id) REFERENCES payments(id))");
addColumn("orders","payout_hold","INTEGER NOT NULL DEFAULT 0");addColumn("orders","stock_restored","INTEGER NOT NULL DEFAULT 0");addColumn("refunds","product_amount","INTEGER NOT NULL DEFAULT 0");addColumn("refunds","delivery_amount","INTEGER NOT NULL DEFAULT 0");db.exec("CREATE TABLE IF NOT EXISTS marketplace_policies(id INTEGER PRIMARY KEY CHECK(id=1),cancellation_before_status TEXT NOT NULL DEFAULT 'Preparing',return_window_days INTEGER NOT NULL DEFAULT 7,merchant_response_hours INTEGER NOT NULL DEFAULT 48,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);INSERT OR IGNORE INTO marketplace_policies(id) VALUES(1);CREATE TABLE IF NOT EXISTS return_cases(id INTEGER PRIMARY KEY,order_id TEXT NOT NULL UNIQUE,opened_by INTEGER NOT NULL,case_type TEXT NOT NULL CHECK(case_type IN('buyer_cancellation','merchant_cancellation','return')),reason TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'open',merchant_response TEXT NOT NULL DEFAULT '',admin_note TEXT NOT NULL DEFAULT '',requested_product_refund INTEGER NOT NULL DEFAULT 0,requested_delivery_refund INTEGER NOT NULL DEFAULT 0,approved_product_refund INTEGER NOT NULL DEFAULT 0,approved_delivery_refund INTEGER NOT NULL DEFAULT 0,return_carrier TEXT NOT NULL DEFAULT '',return_tracking TEXT NOT NULL DEFAULT '',response_due_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(order_id) REFERENCES orders(id),FOREIGN KEY(opened_by) REFERENCES users(id));CREATE TABLE IF NOT EXISTS return_evidence(id INTEGER PRIMARY KEY,case_id INTEGER NOT NULL,user_id INTEGER NOT NULL,label TEXT NOT NULL,url TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(case_id) REFERENCES return_cases(id) ON DELETE CASCADE,FOREIGN KEY(user_id) REFERENCES users(id))");
addColumn("marketplace_policies","delivery_refund_rule","TEXT");addColumn("orders","delivered_at","TEXT");db.exec("CREATE TRIGGER IF NOT EXISTS prevent_late_return BEFORE INSERT ON return_cases WHEN NEW.case_type='return' AND (SELECT status FROM orders WHERE id=NEW.order_id)='Delivered' AND julianday('now')-julianday(COALESCE((SELECT delivered_at FROM orders WHERE id=NEW.order_id),(SELECT created_at FROM orders WHERE id=NEW.order_id)))>(SELECT return_window_days FROM marketplace_policies WHERE id=1) BEGIN SELECT RAISE(ABORT,'Return window has closed'); END");db.prepare("UPDATE return_cases SET status='refunded',approved_product_refund=COALESCE((SELECT product_amount FROM refunds WHERE refunds.order_id=return_cases.order_id),0),approved_delivery_refund=COALESCE((SELECT delivery_amount FROM refunds WHERE refunds.order_id=return_cases.order_id),0),updated_at=CURRENT_TIMESTAMP WHERE EXISTS(SELECT 1 FROM refunds WHERE refunds.order_id=return_cases.order_id) AND status!='refunded'").run();
addColumn("users","email_verified","INTEGER NOT NULL DEFAULT 0");addColumn("users","mfa_secret","TEXT");addColumn("users","mfa_enabled","INTEGER NOT NULL DEFAULT 0");addColumn("users","locked_until","INTEGER NOT NULL DEFAULT 0");addColumn("sessions","created_at","TEXT");addColumn("sessions","last_seen_at","TEXT");addColumn("sessions","ip_address","TEXT DEFAULT ''");addColumn("sessions","user_agent","TEXT DEFAULT ''");addColumn("merchants","payout_changed_at","TEXT");addColumn("merchants","payout_cooldown_until","TEXT");db.exec("CREATE TABLE IF NOT EXISTS auth_tokens(id INTEGER PRIMARY KEY,user_id INTEGER NOT NULL,purpose TEXT NOT NULL,token_hash TEXT NOT NULL UNIQUE,expires_at INTEGER NOT NULL,used_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS auth_attempts(id INTEGER PRIMARY KEY,email TEXT NOT NULL,ip_address TEXT NOT NULL,success INTEGER NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP);CREATE TABLE IF NOT EXISTS risk_events(id INTEGER PRIMARY KEY,user_id INTEGER,merchant_id INTEGER,event_type TEXT NOT NULL,score INTEGER NOT NULL,details TEXT NOT NULL DEFAULT '',status TEXT NOT NULL DEFAULT 'open',created_at TEXT DEFAULT CURRENT_TIMESTAMP,resolved_at TEXT,FOREIGN KEY(user_id) REFERENCES users(id),FOREIGN KEY(merchant_id) REFERENCES merchants(id));");db.prepare("UPDATE users SET email_verified=1 WHERE email IN('merchant@soko.demo','buyer@soko.demo','admin@soko.demo')").run();
db.exec("CREATE TABLE IF NOT EXISTS shipments(id INTEGER PRIMARY KEY,order_id TEXT UNIQUE NOT NULL,carrier TEXT NOT NULL,tracking_number TEXT NOT NULL,tracking_url TEXT NOT NULL DEFAULT '',proof_url TEXT NOT NULL DEFAULT '',estimated_delivery TEXT,status TEXT NOT NULL DEFAULT 'awaiting_verification',submitted_at TEXT DEFAULT CURRENT_TIMESTAMP,verified_at TEXT,verified_by INTEGER,FOREIGN KEY(order_id) REFERENCES orders(id) ON DELETE CASCADE,FOREIGN KEY(verified_by) REFERENCES users(id));CREATE TABLE IF NOT EXISTS shipment_events(id INTEGER PRIMARY KEY,shipment_id INTEGER NOT NULL,status TEXT NOT NULL,message TEXT NOT NULL,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(shipment_id) REFERENCES shipments(id) ON DELETE CASCADE)");
db.exec("CREATE TABLE IF NOT EXISTS merchant_onboarding(merchant_id INTEGER PRIMARY KEY,legal_name TEXT NOT NULL DEFAULT '',phone TEXT NOT NULL DEFAULT '',business_type TEXT NOT NULL DEFAULT '',registration_number TEXT NOT NULL DEFAULT '',address TEXT NOT NULL DEFAULT '',id_type TEXT NOT NULL DEFAULT '',status TEXT NOT NULL DEFAULT 'draft',review_note TEXT NOT NULL DEFAULT '',submitted_at TEXT,reviewed_at TEXT,FOREIGN KEY(merchant_id) REFERENCES merchants(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS merchant_documents(id INTEGER PRIMARY KEY,merchant_id INTEGER NOT NULL,document_type TEXT NOT NULL,original_name TEXT NOT NULL,mime_type TEXT NOT NULL,storage_path TEXT NOT NULL,uploaded_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(merchant_id,document_type),FOREIGN KEY(merchant_id) REFERENCES merchants(id) ON DELETE CASCADE)");
db.exec("CREATE TABLE IF NOT EXISTS notification_preferences(user_id INTEGER PRIMARY KEY,in_app_enabled INTEGER NOT NULL DEFAULT 1,email_enabled INTEGER NOT NULL DEFAULT 1,orders_enabled INTEGER NOT NULL DEFAULT 1,shipping_enabled INTEGER NOT NULL DEFAULT 1,account_enabled INTEGER NOT NULL DEFAULT 1,marketing_enabled INTEGER NOT NULL DEFAULT 0,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS notifications(id INTEGER PRIMARY KEY,user_id INTEGER NOT NULL,type TEXT NOT NULL,category TEXT NOT NULL,title TEXT NOT NULL,message TEXT NOT NULL,link TEXT NOT NULL DEFAULT '',event_key TEXT NOT NULL,read_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,UNIQUE(user_id,event_key),FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);CREATE TABLE IF NOT EXISTS email_outbox(id INTEGER PRIMARY KEY,user_id INTEGER NOT NULL,notification_id INTEGER NOT NULL UNIQUE,recipient TEXT NOT NULL,subject TEXT NOT NULL,body TEXT NOT NULL,status TEXT NOT NULL DEFAULT 'simulated',created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(notification_id) REFERENCES notifications(id) ON DELETE CASCADE)");
addColumn("email_outbox","attempts","INTEGER NOT NULL DEFAULT 0");addColumn("email_outbox","last_error","TEXT NOT NULL DEFAULT ''");addColumn("email_outbox","sent_at","TEXT");
db.exec(`CREATE TRIGGER IF NOT EXISTS notify_payment_confirmed AFTER UPDATE OF status ON payments WHEN NEW.status='confirmed' AND OLD.status!='confirmed' BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'payment_confirmed','orders','Payment confirmed','Your payment for order '||o.id||' was confirmed.','account.html','payment:'||o.id||':confirmed' FROM orders o WHERE o.id=NEW.order_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'new_paid_order','orders','New paid order','Order '||o.id||' is paid and ready to prepare.','merchant.html','order:'||o.id||':merchant-paid' FROM orders o JOIN merchants m ON m.id=o.merchant_id WHERE o.id=NEW.order_id;END;CREATE TRIGGER IF NOT EXISTS notify_shipment_submitted AFTER INSERT ON shipments BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'dispatch_submitted','shipping','Dispatch submitted','Carrier details for order '||o.id||' were submitted for Soko verification.','account.html','shipment:'||o.id||':submitted' FROM orders o WHERE o.id=NEW.order_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT id,'dispatch_review','shipping','Dispatch needs review','Carrier collection for order '||NEW.order_id||' needs verification.','admin.html','shipment:'||NEW.order_id||':review:'||id FROM users WHERE role='admin';END;CREATE TRIGGER IF NOT EXISTS notify_shipment_verified AFTER UPDATE OF status ON shipments WHEN NEW.status='collected_verified' AND OLD.status!='collected_verified' BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'collection_verified','shipping','Order is in transit','Soko verified carrier collection for order '||o.id||'.','account.html','shipment:'||o.id||':verified' FROM orders o WHERE o.id=NEW.order_id;END;CREATE TRIGGER IF NOT EXISTS notify_dispute_changed AFTER UPDATE OF dispute_status ON orders WHEN NEW.dispute_status!=OLD.dispute_status BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) VALUES(NEW.buyer_id,'dispute_'||NEW.dispute_status,'orders','Order support updated','The support status for order '||NEW.id||' is now '||replace(NEW.dispute_status,'_',' ')||'.','account.html','dispute:'||NEW.id||':'||NEW.dispute_status);INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'dispute_'||NEW.dispute_status,'orders','Order support updated','The support status for order '||NEW.id||' is now '||replace(NEW.dispute_status,'_',' ')||'.','merchant.html','dispute:'||NEW.id||':'||NEW.dispute_status||':merchant' FROM merchants m WHERE m.id=NEW.merchant_id;END;CREATE TRIGGER IF NOT EXISTS notify_payout_status AFTER INSERT ON payouts BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'payout_'||NEW.status,'orders','Settlement submitted','Settlement for order '||NEW.order_id||' is now '||NEW.status||'.','merchant.html','payout:'||NEW.order_id||':'||NEW.status FROM merchants m WHERE m.id=NEW.merchant_id;END;CREATE TRIGGER IF NOT EXISTS simulate_notification_email AFTER INSERT ON notifications WHEN COALESCE((SELECT email_enabled FROM notification_preferences WHERE user_id=NEW.user_id),1)=1 BEGIN INSERT OR IGNORE INTO email_outbox(user_id,notification_id,recipient,subject,body) SELECT NEW.user_id,NEW.id,u.email,NEW.title,NEW.message FROM users u WHERE u.id=NEW.user_id;END;`);
db.exec(`CREATE TRIGGER IF NOT EXISTS notify_onboarding_status AFTER UPDATE OF status ON merchant_onboarding WHEN NEW.status!=OLD.status BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'verification_'||NEW.status,'account','Merchant verification updated','Your merchant verification status is now '||replace(NEW.status,'_',' ')||'.','merchant.html','verification:'||NEW.merchant_id||':'||NEW.status FROM merchants m WHERE m.id=NEW.merchant_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT id,'verification_review','account','Merchant verification updated','Merchant #'||NEW.merchant_id||' verification is now '||replace(NEW.status,'_',' ')||'.','admin.html','verification:'||NEW.merchant_id||':'||NEW.status||':admin:'||id FROM users WHERE role='admin';END;CREATE TRIGGER IF NOT EXISTS notify_payout_updated AFTER UPDATE OF status ON payouts WHEN NEW.status!=OLD.status BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'payout_'||NEW.status,'orders','Settlement updated','Settlement for order '||NEW.order_id||' is now '||NEW.status||'.','merchant.html','payout:'||NEW.order_id||':'||NEW.status FROM merchants m WHERE m.id=NEW.merchant_id;END;`);
db.exec(`DROP TRIGGER IF EXISTS simulate_notification_email;CREATE TRIGGER simulate_notification_email AFTER INSERT ON notifications WHEN COALESCE((SELECT email_enabled FROM notification_preferences WHERE user_id=NEW.user_id),1)=1 AND CASE NEW.category WHEN 'orders' THEN COALESCE((SELECT orders_enabled FROM notification_preferences WHERE user_id=NEW.user_id),1) WHEN 'shipping' THEN COALESCE((SELECT shipping_enabled FROM notification_preferences WHERE user_id=NEW.user_id),1) WHEN 'marketing' THEN COALESCE((SELECT marketing_enabled FROM notification_preferences WHERE user_id=NEW.user_id),0) ELSE COALESCE((SELECT account_enabled FROM notification_preferences WHERE user_id=NEW.user_id),1) END=1 BEGIN INSERT OR IGNORE INTO email_outbox(user_id,notification_id,recipient,subject,body) SELECT NEW.user_id,NEW.id,u.email,NEW.title,NEW.message FROM users u WHERE u.id=NEW.user_id;END;`);
db.exec(`CREATE TRIGGER IF NOT EXISTS notify_low_product_stock AFTER UPDATE OF stock ON products WHEN NEW.stock<=3 AND OLD.stock>3 BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'low_stock','orders','Product stock is low',NEW.name||' has '||NEW.stock||' remaining.','merchant.html','stock:product:'||NEW.id||':'||NEW.stock FROM merchants m WHERE m.id=NEW.merchant_id;END;CREATE TRIGGER IF NOT EXISTS notify_low_variant_stock AFTER UPDATE OF stock ON product_variants WHEN NEW.stock<=3 AND OLD.stock>3 BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'low_stock','orders','Product variant stock is low',p.name||' — '||NEW.value||' has '||NEW.stock||' remaining.','merchant.html','stock:variant:'||NEW.id||':'||NEW.stock FROM products p JOIN merchants m ON m.id=p.merchant_id WHERE p.id=NEW.product_id;END;`);
db.exec(`CREATE TRIGGER IF NOT EXISTS notify_return_opened AFTER INSERT ON return_cases BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'return_opened','orders','Order case opened','A '||replace(NEW.case_type,'_',' ')||' case was opened for order '||NEW.order_id||'.','returns.html','return:'||NEW.id||':opened:buyer' FROM orders o WHERE o.id=NEW.order_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'return_opened','orders','Order case needs response','A case was opened for order '||NEW.order_id||'.','returns.html','return:'||NEW.id||':opened:merchant' FROM orders o JOIN merchants m ON m.id=o.merchant_id WHERE o.id=NEW.order_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT id,'return_review','orders','Return or cancellation needs review','Case #'||NEW.id||' for order '||NEW.order_id||' needs review.','returns.html','return:'||NEW.id||':opened:admin:'||id FROM users WHERE role='admin';END;CREATE TRIGGER IF NOT EXISTS notify_return_updated AFTER UPDATE OF status ON return_cases WHEN NEW.status!=OLD.status BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'return_'||NEW.status,'orders','Order case updated','Case #'||NEW.id||' is now '||replace(NEW.status,'_',' ')||'.','returns.html','return:'||NEW.id||':'||NEW.status||':buyer' FROM orders o WHERE o.id=NEW.order_id;INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT m.user_id,'return_'||NEW.status,'orders','Order case updated','Case #'||NEW.id||' is now '||replace(NEW.status,'_',' ')||'.','returns.html','return:'||NEW.id||':'||NEW.status||':merchant' FROM orders o JOIN merchants m ON m.id=o.merchant_id WHERE o.id=NEW.order_id;END;`);
db.exec(`CREATE TRIGGER IF NOT EXISTS notify_shipment_status AFTER INSERT ON shipment_events BEGIN INSERT OR IGNORE INTO notifications(user_id,type,category,title,message,link,event_key) SELECT o.buyer_id,'shipment_'||NEW.status,'shipping','Delivery update','Order '||o.id||': '||NEW.message,'account.html','shipment-event:'||NEW.id||':'||o.buyer_id FROM shipments s JOIN orders o ON o.id=s.order_id WHERE s.id=NEW.shipment_id;END;`);
db.exec("CREATE TRIGGER IF NOT EXISTS prevent_expired_payment_confirmation BEFORE UPDATE OF status ON payments WHEN OLD.status='expired' AND NEW.status='confirmed' BEGIN SELECT RAISE(ABORT,'Payment reference expired'); END");
db.prepare("UPDATE orders SET subtotal=total,merchant_amount=total WHERE merchant_amount=0 AND status!='Awaiting payment'").run();
const currencies={Nigeria:"NGN",Ghana:"GHS",Kenya:"KES"};function hashPassword(password,salt=crypto.randomBytes(16).toString("hex")){return `${salt}:${crypto.scryptSync(password,salt,64).toString("hex")}`}function validPassword(password,stored){const [salt,key]=stored.split(":");return crypto.timingSafeEqual(Buffer.from(key,"hex"),crypto.scryptSync(password,salt,64))}
function seed(){if(db.prepare("SELECT id FROM users WHERE email=?").get("merchant@soko.demo"))return;const result=db.prepare("INSERT INTO users(email,password_hash,role,name) VALUES(?,?,?,?)").run("merchant@soko.demo",hashPassword("SokoDemo123!"),"merchant","Amara Okafor");const merchant=db.prepare("INSERT INTO merchants(user_id,store_name,country,description,verified) VALUES(?,?,?,?,1)").run(result.lastInsertRowid,"Amara Organics","Nigeria","Small-batch natural skincare made in Lagos.");const add=db.prepare("INSERT INTO products(merchant_id,name,category,price,stock,emoji,color,description) VALUES(?,?,?,?,?,?,?,?)");add.run(merchant.lastInsertRowid,"Cocoa & shea body cream","beauty",18500,24,"🧴","#ead6ac","Deeply nourishing body cream.");add.run(merchant.lastInsertRowid,"African black soap trio","beauty",12000,8,"🧼","#bdd0b1","Three traditionally made cleansing bars.");add.run(merchant.lastInsertRowid,"Baobab face oil","beauty",24000,3,"✨","#d6c4df","Lightweight botanical face oil.");const buyer=db.prepare("INSERT INTO users(email,password_hash,role,name) VALUES(?,?,?,?)").run("buyer@soko.demo",hashPassword("SokoDemo123!"),"buyer","Kemi Adeyemi");db.prepare("INSERT INTO orders(id,buyer_id,merchant_id,currency,total,status,customer_name,destination) VALUES(?,?,?,?,?,?,?,?)").run("SK26071184",buyer.lastInsertRowid,merchant.lastInsertRowid,"NGN",37000,"Payment confirmed","Kemi A.","London, UK")}
seed();
