function seedCatalogue(){const images=[["Cocoa & shea body cream","/assets/products/cocoa-shea-cream.png"],["African black soap trio","/assets/products/african-black-soap.png"],["Baobab face oil","/assets/products/baobab-face-oil.png"]],update=db.prepare("UPDATE products SET image_url=? WHERE name=?");for(const [name,url] of images)update.run(url,name);const add=db.prepare("INSERT OR IGNORE INTO product_variants(product_id,name,value,stock,price_adjustment) VALUES(?,?,?,?,?)"),addImage=db.prepare("INSERT INTO product_images(product_id,url,position) SELECT ?,?,0 WHERE NOT EXISTS(SELECT 1 FROM product_images WHERE product_id=?)");for(const p of db.prepare("SELECT id,name,stock,image_url FROM products").all()){if(p.image_url)addImage.run(p.id,p.image_url,p.id);if(p.name.includes("cream")){add.run(p.id,"Size","100 ml",Math.max(1,p.stock-8),0);add.run(p.id,"Size","200 ml",8,9500)}else if(p.name.includes("soap")){add.run(p.id,"Pack","3 bars",p.stock,0);add.run(p.id,"Pack","6 bars",4,10000)}else if(p.name.includes("oil")){add.run(p.id,"Size","30 ml",p.stock,0);add.run(p.id,"Size","50 ml",2,11000)}}}seedCatalogue();
