const requestWindows=new Map();function rateAllowed(req){const key=requestIp(req),now=Date.now(),window=requestWindows.get(key)||{start:now,count:0};if(now-window.start>60000){window.start=now;window.count=0}window.count++;requestWindows.set(key,window);return window.count<=180}const server=http.createServer(async(req,res)=>{const url=new URL(req.url,"http://localhost");try{if(url.pathname.startsWith("/api/")&&!rateAllowed(req))return send(res,429,{error:"Too many requests. Please slow down."},{"Retry-After":"60"});if(url.pathname.startsWith("/api/"))await api(req,res,url);else staticFile(req,res,url)}catch(e){console.error(e);send(res,500,{error:"Something went wrong"})}finally{deliverEmailOutbox().catch(error=>console.error("Email delivery flush failed",error.message))}});const port=Number(process.env.PORT||4173);server.listen(port,()=>console.log(`Soko running at http://localhost:${port}`));const backupHours=Number(process.env.BACKUP_INTERVAL_HOURS||0);if(backupHours>0){const runBackup=()=>{const child=spawn(process.execPath,[path.join(ROOT,"scripts","backup.js")],{env:process.env,stdio:"inherit"});child.on("error",error=>console.error("Scheduled backup failed",error.message))};runBackup();setInterval(runBackup,backupHours*3600000).unref()}
